<p class="updated" id="updated">Connecting...</p>

<script>
function renderPoints(points) {
  var sel = document.getElementById('pointsel');
  if (!sel) return;
  var cur = sel.value;
  sel.innerHTML = '';
  points.forEach(function(p){ var o = document.createElement('option'); o.value = p.id; o.textContent = p.name; sel.appendChild(o); });
  if (cur) sel.value = cur;
  var add = document.getElementById('seqadd');
  if (add) {
    var curAdd = add.value;
    add.innerHTML = '';
    points.forEach(function(p){ var o = document.createElement('option'); o.value = p.id; o.textContent = p.name; add.appendChild(o); });
    if (curAdd) add.value = curAdd;
  }
  renderSeq();
}
function goPoint() {
  var sel = document.getElementById('pointsel');
  if (!sel || !sel.value) return;
  sendMove({ goto: sel.value }, 'Go ' + sel.options[sel.selectedIndex].text);
}
function savePoint() {
  var name = (document.getElementById('ptname').value || '').trim();
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = 'Saving point...';
  fetch('/robot/savepoint', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ name:name }) })
    .then(function(r){ return r.json(); })
    .then(function(res){
      if (res.ok) { toast.style.color='#3fb950'; toast.textContent='Saved: ' + res.name; document.getElementById('ptname').value=''; renderPoints(res.points||[]); }
      else { toast.style.color='#f85149'; toast.textContent='Error: ' + (res.error||'failed'); }
    })
    .catch(function(){ toast.style.color='#f85149'; toast.textContent='Connection error'; });
}
function deletePoint() {
  var sel = document.getElementById('pointsel');
  if (!sel || !sel.value) return;
  var toast = document.getElementById('toast');
  toast.style.color='#8b949e'; toast.textContent='Deleting...';
  fetch('/robot/deletepoint', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id: sel.value }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ if(res.ok){ toast.style.color='#3fb950'; toast.textContent='Deleted'; renderPoints(res.points||[]); } else { toast.style.color='#f85149'; toast.textContent='Error'; } })
    .catch(function(){ toast.style.color='#f85149'; toast.textContent='Connection error'; });
}
function ctrl(state) {
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = (state === 'motoroff' ? 'Stopping...' : 'Recovering...');
  fetch('/robot/ctrlstate', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ state:state }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ toast.style.color = res.ok ? '#3fb950' : '#f85149'; toast.textContent = res.ok ? (state === 'motoroff' ? 'Motors OFF' : 'Motors ON') : ('Error: ' + (res.error || res.status)); })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; });
}
function jogJoint(tok) {
  var step = parseInt(document.getElementById('joint-deg').value) || 5;
  sendMove({ joint: tok, step: step }, 'Joint ' + tok + ' ' + step + 'deg');
}
function setHome() {
  if (!confirm('Set HOME to the current pose? (saved on the controller)')) return;
  sendMove({ sethome: true }, 'Set Home');
}
var seqSteps = [];
function renderSeq() {
  var list = document.getElementById('seqlist');
  if (!list) return;
  list.innerHTML = '';
  if (!seqSteps.length) { var li = document.createElement('li'); li.className = 'empty'; li.textContent = 'No steps yet \u2014 add points above.'; list.appendChild(li); return; }
  seqSteps.forEach(function(s, i){
    var li = document.createElement('li');
    li.innerHTML = '<span class="sidx">' + (i + 1) + '</span><span class="sname">' + s.name + '</span>' +
      '<button onclick="seqUp(' + i + ')"' + (i === 0 ? ' disabled' : '') + '>&#9650;</button>' +
      '<button onclick="seqDown(' + i + ')"' + (i === seqSteps.length - 1 ? ' disabled' : '') + '>&#9660;</button>' +
      '<button class="x" onclick="seqDel(' + i + ')">&times;</button>';
    list.appendChild(li);
  });
}
function addSeqStep() {
  var sel = document.getElementById('seqadd');
  if (!sel || !sel.value) return;
  seqSteps.push({ id: sel.value, name: sel.options[sel.selectedIndex].text });
  renderSeq();
}
function seqUp(i)   { if (i <= 0) return; var t = seqSteps[i-1]; seqSteps[i-1] = seqSteps[i]; seqSteps[i] = t; renderSeq(); }
function seqDown(i) { if (i >= seqSteps.length - 1) return; var t = seqSteps[i+1]; seqSteps[i+1] = seqSteps[i]; seqSteps[i] = t; renderSeq(); }
function seqDel(i)  { seqSteps.splice(i, 1); renderSeq(); }
function runSeq() {
  var steps = seqSteps.map(function(s){ return { name: s.name }; });
  if (!steps.length) return;
  var dwell = parseInt(document.getElementById('seq-dwell').value) || 0;
  var loop = document.getElementById('seq-loop').checked;
  var pingpong = document.getElementById('seq-pingpong').checked;
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = 'Running sequence (' + steps.length + ')...';
  fetch('/robot/sequence', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ steps:steps, dwell:dwell, loop:loop, pingpong:pingpong }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ toast.style.color = res.ok ? '#3fb950' : '#f85149'; toast.textContent = res.ok ? ('Sequence started: ' + res.count + ' points') : ('Error: ' + (res.error || 'failed')); })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; });
}
function stopSeq() {
  fetch('/robot/sequence/stop', { method:'POST' })
    .then(function(r){ return r.json(); })
    .then(function(){ var t = document.getElementById('toast'); t.style.color = '#d29922'; t.textContent = 'Sequence stop requested'; });
}
function update() {
  fetch('/robot/data')
    .then(r => r.json())
    .then(d => {
      document.getElementById('ctrlstate').textContent = d.ctrlstate || '-';
      document.getElementById('opmode').textContent = d.opmode || '-';
      document.getElementById('rapid').textContent = d.rapid || '-';
      document.getElementById('speed').textContent = (d.speed || '0') + '%';
      document.getElementById('speedbar').style.width = (d.speed || 0) + '%';
      document.getElementById('px').textContent = d.x || '-';
      document.getElementById('py').textContent = d.y || '-';
      document.getElementById('pz').textContent = d.z || '-';
      document.getElementById('j1').textContent = d.j1 || '-';
      document.getElementById('j2').textContent = d.j2 || '-';
      document.getElementById('j3').textContent = d.j3 || '-';
      document.getElementById('j4').textContent = d.j4 || '-';
      document.getElementById('j5').textContent = d.j5 || '-';
      document.getElementById('j6').textContent = d.j6 || '-';
      document.getElementById('updated').textContent = 'Last update: ' + d.updated;
      renderPoints(d.points || []);
      var led = document.getElementById('led');
      var colors = { motoron:'green', guardstop:'yellow', emergencystop:'red', sysfail:'red' };
      led.className = 'led ' + (colors[d.ctrlstate] || 'grey');
    })
    .catch(function() {
      document.getElementById('updated').textContent = 'Connection error — retrying...';
    });
}
function sendMove(body, label) {
  var toast = document.getElementById('toast');
  var btns = document.querySelectorAll('.btn');
  btns.forEach(function(b){ b.disabled = true; });
  toast.style.color = '#8b949e';
  toast.textContent = 'Sending ' + label + '...';
  fetch('/robot/move', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body) })
    .then(function(r){ return r.json(); })
    .then(function(res){
      if (res.ok) { toast.style.color = '#3fb950'; toast.textContent = 'OK: ' + label + (res.ack ? ' (' + res.ack + ')' : ''); }
      else { toast.style.color = '#f85149'; toast.textContent = 'Error: ' + (res.error || 'failed'); }
    })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; })
    .finally(function(){ btns.forEach(function(b){ b.disabled = false; }); });
}
function move(key) {
  var names = { home:'Home', p1:'Point 1', p2:'Point 2', p3:'Point 3' };
  sendMove({ routine:key }, names[key] || key);
}
function jog(token) {
  var rot = token.charAt(0) === 'R';
  var step = rot ? (parseInt(document.getElementById('ang-deg').value) || 5)
                 : (parseInt(document.getElementById('lin-mm').value) || 10);
  sendMove({ jog:token, step:step }, 'Jog ' + token + ' ' + step + (rot ? 'deg' : 'mm'));
}
function syncLin(src) {
  var r = document.getElementById('lin-range'), mm = document.getElementById('lin-mm');
  if (src === 'range') { mm.value = r.value * 10; }
  else { var v = Math.max(1, Math.min(50, parseInt(mm.value) || 10)); mm.value = v; r.value = Math.round(v / 10) || 1; }
  document.getElementById('lin-cm').textContent = (mm.value / 10);
}
update();
setInterval(update, 200);
</script>
</body>
</html>`;
return msg;

var d = flow.get('robot_data') || {};
msg.payload = Object.assign({}, d, { points: msg.payload });
msg.statusCode = 200;
return msg;

var p = msg.payload || {};
if (p.routine || p.sethome) {
    msg.payload = { command: p.sethome ? 'SETHOME' : p.routine.toUpperCase() };
    return [msg, null, null, null, null];
}
if (p.jog) {
    msg.payload = { axis: p.jog.slice(0,-1), dir: p.jog.slice(-1), step: p.step };
    return [null, msg, null, null, null];
}
if (p.joint) {
    msg.payload = { joint: p.joint.slice(0,-1), dir: p.joint.slice(-1), step: p.step };
    return [null, null, msg, null, null];
}
if (p.goto) {
    msg.payload = { name: p.goto, id: p.goto };
    return [null, null, null, msg, null];
}
msg.statusCode = 400;
msg.payload = { ok: false, error: 'unknown command' };
return [null, null, null, null, msg];

msg.payload.name = msg.payload.point ? msg.payload.point.name : '';
msg.statusCode = 200;
return msg;

var p = msg.payload || {};
var steps = p.steps || [];
// immediate HTTP reply
var reply = { req: msg.req, res: msg.res,
